def is_english_text(text):
    """Simple heuristic: >=80% ASCII characters = English."""
    if not text.strip():
        return False
    ascii_chars = sum(1 for c in text if ord(c) < 128)
    return ascii_chars / len(text) >= 0.8

def scrape_page(url):
    """Scrape and extract clean English text from a URL."""
    try:
        resp = requests.get(url, headers=HEADERS, timeout=15)
        resp.raise_for_status()
        soup = BeautifulSoup(resp.text, 'lxml')
        # Remove boilerplate tags
        for tag in soup(['script', 'style', 'nav', 'footer',
                         'header', 'noscript', 'meta', 'link',
                         'iframe', 'form', 'button']):
            tag.decompose()
        # Get visible text
        text = soup.get_text(separator=' ')
        # Keep only English sentences
        lines = [ln.strip() for ln in text.splitlines()]
        eng_lines = [ln for ln in lines if len(ln) > 30 and is_english_text(ln)]
        return ' '.join(eng_lines)
    except Exception as e:
        print(f'  [WARN] Failed: {url} — {e}')
        return ''

print('Starting IIT Jodhpur data collection...')
raw_documents = []
for url in URLS:
    print(f'  Scraping: {url}')
    text = scrape_page(url)
    if len(text) > 100:
        raw_documents.append({'url': url, 'text': text})
    time.sleep(0.8)  # polite crawl delay

print(f'\n✅ Successfully scraped {len(raw_documents)} documents.')

