# ============================================================
# TASK 1 — STEP 3: Preprocessing Pipeline
# ============================================================
import string
from nltk.tokenize import sent_tokenize, word_tokenize
from nltk.corpus import stopwords

STOP_WORDS = set(stopwords.words('english'))

def preprocess_text(text):
    """
    Full preprocessing pipeline:
      (i)  Remove boilerplate / formatting artifacts
      (ii) Tokenize
      (iii) Lowercase
      (iv) Remove excessive punctuation & non-textual content
    Returns list of sentences, each a list of tokens.
    """
    # (i) Remove URLs, emails, special formatting
    text = re.sub(r'http\S+|www\.\S+', ' ', text)
    text = re.sub(r'\S+@\S+', ' ', text)
    text = re.sub(r'\|+', ' ', text)
    text = re.sub(r'[-–—]{2,}', ' ', text)
    text = re.sub(r'[^\x00-\x7F]+', ' ', text)  # remove non-ASCII
    text = re.sub(r'\s+', ' ', text).strip()

    # (ii) Sentence tokenize
    sentences = sent_tokenize(text)

    processed_sentences = []
    for sent in sentences:
        # (iii) Lowercase
        sent = sent.lower()
        # (iv) Word tokenize & remove punctuation / digits / short tokens
        tokens = word_tokenize(sent)
        tokens = [
            t for t in tokens
            if t.isalpha()          # only alphabetic
            and len(t) >= 2         # min length 2
        ]
        if len(tokens) >= 3:        # skip trivial sentences
            processed_sentences.append(tokens)
    return processed_sentences

# Apply to all documents
all_sentences = []
for doc in raw_documents:
    sents = preprocess_text(doc['text'])
    all_sentences.extend(sents)

