QUERY_WORDS = ['research', 'student', 'phd', 'exam', 'department']

def nearest_neighbors(model, word, topn=5, model_name=''):
    wv = model.wv
    if word not in wv:
        print(f'  [{model_name}] "{word}" not in vocabulary.')
        return []
    return wv.most_similar(word, topn=topn)

