# ============================================================
# TASK 4: PCA & t-SNE Visualizations
# ============================================================
import numpy as np
from sklearn.decomposition import PCA
from sklearn.manifold import TSNE
import matplotlib.pyplot as plt
import matplotlib.patches as mpatches

# Define semantic clusters of words to visualize
CLUSTER_WORDS = {
    'Academic Programs': ['btech', 'mtech', 'phd', 'undergraduate', 'postgraduate',
                          'doctorate', 'degree', 'program', 'curriculum'],
    'Research':          ['research', 'lab', 'project', 'publication', 'journal',
                          'thesis', 'dissertation', 'funded', 'grant'],
    'Examinations':      ['exam', 'semester', 'grade', 'marks', 'cgpa', 'sgpa',
                          'assessment', 'quiz', 'evaluation'],
    'People':            ['student', 'faculty', 'professor', 'scholar', 'director',
                          'advisor', 'researcher', 'engineer'],
    'Departments':       ['cse', 'electrical', 'mechanical', 'civil', 'chemical',
                          'physics', 'mathematics', 'bioscience'],
}

COLORS = ['#e74c3c', '#3498db', '#2ecc71', '#f39c12', '#9b59b6']

def get_word_vectors(model_wv, cluster_dict):
    """Extract vectors and labels for words present in vocabulary."""
    vectors, labels, colors = [], [], []
    for (cluster, color) in zip(cluster_dict.items(), COLORS):
        (cluster_name, words), clr = cluster, color
        for w in words:
            if w in model_wv:
                vectors.append(model_wv[w])
                labels.append(w)
                colors.append(clr)
    return np.array(vectors), labels, colors

def plot_embeddings(vectors, labels, colors, title, method='PCA'):
    """Reduce dimensions and plot with cluster coloring."""
    if len(vectors) < 2:
        print(f'Not enough words to plot for {title}')
        return

    if method == 'PCA':
        reducer = PCA(n_components=2, random_state=42)
        coords = reducer.fit_transform(vectors)
        var = reducer.explained_variance_ratio_
        xlabel = f'PC1 ({var[0]*100:.1f}% var)'
        ylabel = f'PC2 ({var[1]*100:.1f}% var)'
    else:  # t-SNE
        perplexity = min(5, len(vectors) - 1)
        reducer = TSNE(n_components=2, perplexity=perplexity,
                       random_state=42, n_iter=1000)
        coords = reducer.fit_transform(vectors)
        xlabel, ylabel = 'Dim-1', 'Dim-2'

    fig, ax = plt.subplots(figsize=(13, 8))
    ax.scatter(coords[:, 0], coords[:, 1], c=colors, s=80, alpha=0.85)

    for i, (lbl, (x, y)) in enumerate(zip(labels, coords)):
        ax.annotate(lbl, (x, y), fontsize=8.5, alpha=0.9,
                    xytext=(4, 4), textcoords='offset points')

    # Legend
    patches = [mpatches.Patch(color=c, label=cl)
               for cl, c in zip(CLUSTER_WORDS.keys(), COLORS)]
    ax.legend(handles=patches, loc='best', fontsize=9)
    ax.set_title(title, fontsize=13, pad=10)
    ax.set_xlabel(xlabel)
    ax.set_ylabel(ylabel)
    ax.grid(True, alpha=0.3)
    plt.tight_layout()
    fname = title.replace(' ', '_').replace('/', '_') + '.png'
    plt.savefig(fname, dpi=150)
    plt.show()
    print(f'Saved: {fname}')

# --- CBOW Visualizations ---
vecs_c, lbls_c, clrs_c = get_word_vectors(best_cbow.wv, CLUSTER_WORDS)
print(f'CBOW: {len(lbls_c)} words found in vocabulary for visualization')
plot_embeddings(vecs_c, lbls_c, clrs_c, 'CBOW — PCA 2D Word Embedding Visualization', method='PCA')
plot_embeddings(vecs_c, lbls_c, clrs_c, 'CBOW — t-SNE 2D Word Embedding Visualization', method='tSNE')

# --- Skip-gram Visualizations ---
vecs_s, lbls_s, clrs_s = get_word_vectors(best_sg.wv, CLUSTER_WORDS)
print(f'SG: {len(lbls_s)} words found in vocabulary for visualization')
plot_embeddings(vecs_s, lbls_s, clrs_s, 'Skip-gram — PCA 2D Word Embedding Visualization', method='PCA')
plot_embeddings(vecs_s, lbls_s, clrs_s, 'Skip-gram — t-SNE 2D Word Embedding Visualization', method='tSNE')

# ============================================================
# Cosine Similarity Heatmap between Key Words
# ============================================================
import seaborn as sns

KEY_WORDS = ['research', 'student', 'phd', 'exam', 'faculty',
             'btech', 'mtech', 'department', 'semester', 'thesis']

def cosine_heatmap(model, words, title):
    wv = model.wv
    present = [w for w in words if w in wv]
    if len(present) < 2:
        print(f'Not enough words for heatmap: {title}')
        return
    mat = np.zeros((len(present), len(present)))
    for i, w1 in enumerate(present):
        for j, w2 in enumerate(present):
            mat[i, j] = wv.similarity(w1, w2)
    fig, ax = plt.subplots(figsize=(9, 7))
    sns.heatmap(mat, xticklabels=present, yticklabels=present,
                annot=True, fmt='.2f', cmap='YlOrRd', ax=ax,
                linewidths=0.4, linecolor='white', vmin=0, vmax=1)
    ax.set_title(title, fontsize=12, pad=10)
    plt.tight_layout()
    fname = title.replace(' ', '_') + '.png'
    plt.savefig(fname, dpi=150)
    plt.show()
    print(f'Saved: {fname}')

cosine_heatmap(best_cbow, KEY_WORDS, 'CBOW_Cosine_Similarity_Heatmap')
cosine_heatmap(best_sg,   KEY_WORDS, 'SkipGram_Cosine_Similarity_Heatmap')

# ============================================================
# Interpretation / Clustering Discussion
# ============================================================
print("""
VISUALIZATION INTERPRETATION
==============================

PCA Analysis:
  - PCA projects high-dimensional embeddings into 2D principal components.
  - Words from the same semantic cluster (e.g. exams: 'grade', 'sgpa', 'cgpa')
    tend to appear closer together in PCA space.
  - The first two PCs capture a portion of total variance; some clusters
    may overlap if their variance is not aligned with the top-2 PCs.

t-SNE Analysis:
  - t-SNE preserves local neighborhood structure, so semantically related
    words form tighter clusters.
  - Academic programs cluster (btech, mtech, phd) should appear near each other.
  - Exam-related terms and research terms form distinct groups.

CBOW vs Skip-gram Differences:
  - CBOW averages context vectors → smoother, more compressed representation.
    Frequent words are well-represented; rare words may be less distinct.
  - Skip-gram (Negative Sampling) trains on individual context pairs →
    richer representations for rare/domain-specific words like 'dissertation',
    'sgpa', 'viva'.
  - In t-SNE plots, Skip-gram clusters are often tighter and more separated,
    especially for domain-specific terminology.
  - CBOW clusters may show more overlap between related but distinct groups
    (e.g., academic programs and examinations).
""")

