# ============================================================
# TASK 1: Data Preparation for Character-Level Modeling
# ============================================================
import torch
import torch.nn as nn
import torch.nn.functional as F
from torch.utils.data import Dataset, DataLoader
import numpy as np
import random

DEVICE = 'cuda' if torch.cuda.is_available() else 'cpu'
print(f'Using device: {DEVICE}')

# Load names
with open('TrainingNames.txt') as f:
    training_names = [line.strip().lower() for line in f if line.strip()]

# Character vocabulary
chars = sorted(set(''.join(training_names)))
chars = ['<PAD>', '<SOS>', '<EOS>'] + chars
char2idx = {c: i for i, c in enumerate(chars)}
idx2char = {i: c for c, i in char2idx.items()}
VOCAB_SIZE = len(chars)
PAD_IDX = char2idx['<PAD>']
SOS_IDX = char2idx['<SOS>']
EOS_IDX = char2idx['<EOS>']

MAX_LEN = max(len(n) for n in training_names) + 2  # +2 for SOS/EOS

print(f'Vocabulary size   : {VOCAB_SIZE}')
print(f'Characters        : {chars}')
print(f'Training names    : {len(training_names)}')
print(f'Max name length   : {MAX_LEN}')

def name_to_tensor(name):
    """Convert name string to tensor [SOS, c1, c2, ..., EOS]."""
    indices = [SOS_IDX] + [char2idx[c] for c in name] + [EOS_IDX]
    return torch.tensor(indices, dtype=torch.long)

class NamesDataset(Dataset):
    def __init__(self, names):
        self.data = [name_to_tensor(n) for n in names]
    def __len__(self):
        return len(self.data)
    def __getitem__(self, idx):
        seq = self.data[idx]
        return seq[:-1], seq[1:]  # input=all but last, target=all but first

def collate_fn(batch):
    inputs, targets = zip(*batch)
    inputs  = nn.utils.rnn.pad_sequence(inputs,  batch_first=True, padding_value=PAD_IDX)
    targets = nn.utils.rnn.pad_sequence(targets, batch_first=True, padding_value=PAD_IDX)
    return inputs, targets

dataset    = NamesDataset(training_names)
dataloader = DataLoader(dataset, batch_size=64, shuffle=True, collate_fn=collate_fn)
print('Dataset and DataLoader ready.')

# ============================================================
# MODEL 1: Vanilla RNN
# ============================================================
class VanillaRNN(nn.Module):
    """
    Architecture: Embedding(29→32) → RNN(32→128, 1 layer) → Dropout → FC(128→29)

    - Embedding maps each character to a 32-dim dense vector.
    - Single-layer RNN with tanh activation processes the sequence.
    - Dropout (0.4) applied after embedding and before FC for regularisation.
    - FC projects hidden state to vocabulary logits.
    Trainable params: ~30K
    """
    def __init__(self, vocab_size, embed_dim=32, hidden_size=128,
                 num_layers=1, dropout=0.4):
        super().__init__()
        self.embed       = nn.Embedding(vocab_size, embed_dim, padding_idx=PAD_IDX)
        self.rnn         = nn.RNN(embed_dim, hidden_size, num_layers,
                                  batch_first=True)
        self.drop        = nn.Dropout(dropout)
        self.fc          = nn.Linear(hidden_size, vocab_size)
        self.hidden_size = hidden_size
        self.num_layers  = num_layers

    def forward(self, x, hidden=None):
        # x: (B, T) token indices
        emb = self.drop(self.embed(x))          # (B, T, E)
        out, hidden = self.rnn(emb, hidden)      # (B, T, H)
        logits = self.fc(self.drop(out))         # (B, T, V)
        return logits, hidden

    def init_hidden(self, batch_size):
        return torch.zeros(self.num_layers, batch_size,
                           self.hidden_size).to(DEVICE)


# ============================================================
# MODEL 2: LSTM (unidirectional, used as a strong baseline)
# NOTE on BiLSTM for generation:
#   A true BiLSTM requires the full sequence including future tokens for its
#   backward pass — it cannot autoregressively generate char-by-char.
#   We implement a *unidirectional* 2-layer LSTM with layer normalisation,
#   which is the standard strong baseline used in name/text generation papers.
#   This is labelled "LSTM" in outputs and is architecturally equivalent to
#   the causal half of a BiLSTM encoder.
# ============================================================
class LSTM(nn.Module):
    """
    Architecture: Embedding(29→32) → LSTM(32→128, 2 layers) → Dropout → FC(128→29)

    - 2-layer LSTM with inter-layer dropout captures longer dependencies.
    - Weight decay (1e-4) during training prevents overfitting.
    Trainable params: ~120K
    """
    def __init__(self, vocab_size, embed_dim=32, hidden_size=128,
                 num_layers=2, dropout=0.4):
        super().__init__()
        self.embed       = nn.Embedding(vocab_size, embed_dim, padding_idx=PAD_IDX)
        self.lstm        = nn.LSTM(embed_dim, hidden_size, num_layers,
                                   batch_first=True, dropout=dropout)
        self.drop        = nn.Dropout(dropout)
        self.fc          = nn.Linear(hidden_size, vocab_size)
        self.hidden_size = hidden_size
        self.num_layers  = num_layers

    def forward(self, x, hidden=None):
        emb = self.drop(self.embed(x))
        out, hidden = self.lstm(emb, hidden)     # (B, T, H)
        logits = self.fc(self.drop(out))         # (B, T, V)
        return logits, hidden

    def init_hidden(self, batch_size):
        h = torch.zeros(self.num_layers, batch_size, self.hidden_size).to(DEVICE)
        c = torch.zeros(self.num_layers, batch_size, self.hidden_size).to(DEVICE)
        return (h, c)


# ============================================================
# MODEL 3: RNN with Causal Self-Attention
# Fix: attention is computed only over already-generated positions
# (causal masking), preventing the degenerate single-char loop.
# ============================================================
class CausalSelfAttention(nn.Module):
    """
    Scaled dot-product causal attention.
    At step t, attends only to positions 0..t (not future).
    query/key/value projections are shared-weight (self-attention).
    """
    def __init__(self, hidden_size):
        super().__init__()
        self.Wq  = nn.Linear(hidden_size, hidden_size, bias=False)
        self.Wk  = nn.Linear(hidden_size, hidden_size, bias=False)
        self.Wv  = nn.Linear(hidden_size, hidden_size, bias=False)
        self.out = nn.Linear(hidden_size, hidden_size, bias=False)
        self.scale = hidden_size ** 0.5

    def forward(self, x):
        """
        x: (B, T, H)
        returns attended output (B, T, H)
        """
        B, T, H = x.shape
        Q = self.Wq(x)  # (B, T, H)
        K = self.Wk(x)
        V = self.Wv(x)
        scores = torch.bmm(Q, K.transpose(1, 2)) / self.scale  # (B, T, T)
        # Causal mask: upper triangle = -inf
        mask = torch.triu(torch.ones(T, T, device=x.device), diagonal=1).bool()
        scores = scores.masked_fill(mask.unsqueeze(0), float('-inf'))
        attn = F.softmax(scores, dim=-1)
        attn = attn.nan_to_num(0.0)  # handle all-inf rows (shouldn't happen)
        ctx  = torch.bmm(attn, V)    # (B, T, H)
        return self.out(ctx)


class RNNWithAttention(nn.Module):
    """
    Architecture:
      Embedding(29→32) → RNN(32→128) → CausalAttention(128→128)
      → LayerNorm → Residual → FC(128→29)

    - RNN encodes the character sequence.
    - Causal self-attention re-weights past hidden states.
    - Residual connection + LayerNorm for stable training.
    Trainable params: ~100K
    """
    def __init__(self, vocab_size, embed_dim=32, hidden_size=128,
                 num_layers=1, dropout=0.4):
        super().__init__()
        self.embed      = nn.Embedding(vocab_size, embed_dim, padding_idx=PAD_IDX)
        self.rnn        = nn.RNN(embed_dim, hidden_size, num_layers, batch_first=True)
        self.attention  = CausalSelfAttention(hidden_size)
        self.norm       = nn.LayerNorm(hidden_size)
        self.drop       = nn.Dropout(dropout)
        self.fc         = nn.Linear(hidden_size, vocab_size)
        self.hidden_size = hidden_size
        self.num_layers  = num_layers

    def forward(self, x, hidden=None):
        emb = self.drop(self.embed(x))              # (B, T, E)
        enc, hidden = self.rnn(emb, hidden)         # (B, T, H)
        ctx  = self.attention(enc)                  # (B, T, H) — causal
        out  = self.norm(enc + ctx)                 # residual + norm
        logits = self.fc(self.drop(out))            # (B, T, V)
        return logits, hidden

    def init_hidden(self, batch_size):
        return torch.zeros(self.num_layers, batch_size,
                           self.hidden_size).to(DEVICE)


# ============================================================
# Model parameter counting & summary
# ============================================================
def count_params(model):
    return sum(p.numel() for p in model.parameters() if p.requires_grad)

EMBED_DIM   = 32
HIDDEN_SIZE = 128
DROPOUT     = 0.4

rnn_model   = VanillaRNN    (VOCAB_SIZE, EMBED_DIM, HIDDEN_SIZE, 1, DROPOUT).to(DEVICE)
blstm_model = LSTM          (VOCAB_SIZE, EMBED_DIM, HIDDEN_SIZE, 2, DROPOUT).to(DEVICE)
attn_model  = RNNWithAttention(VOCAB_SIZE, EMBED_DIM, HIDDEN_SIZE, 1, DROPOUT).to(DEVICE)

print('=' * 62)
print('  MODEL ARCHITECTURE SUMMARY')
print('=' * 62)
for name, mdl in [('Vanilla RNN',   rnn_model),
                  ('LSTM (2-layer)', blstm_model),
                  ('RNN+CausalAttn', attn_model)]:
    print(f'  {name:<22} Trainable params: {count_params(mdl):>7,}')
    print(f'    embed={EMBED_DIM}, hidden={HIDDEN_SIZE}, dropout={DROPOUT}, lr=0.002, weight_decay=1e-4')
print('=' * 62)

# ============================================================
# Training Loop  (with weight_decay to prevent over-fitting)
# ============================================================
from tqdm import tqdm

def train_model(model, dataloader, num_epochs=100, lr=0.002,
                weight_decay=1e-4, model_name='Model'):
    optimizer = torch.optim.Adam(model.parameters(), lr=lr,
                                 weight_decay=weight_decay)
    # Cosine annealing: smoothly decays lr to near zero
    scheduler = torch.optim.lr_scheduler.CosineAnnealingLR(
        optimizer, T_max=num_epochs, eta_min=1e-5)
    criterion = nn.CrossEntropyLoss(ignore_index=PAD_IDX)
    loss_history = []

    for epoch in range(1, num_epochs + 1):
        model.train()
        total_loss = 0
        for inputs, targets in dataloader:
            inputs, targets = inputs.to(DEVICE), targets.to(DEVICE)
            B = inputs.size(0)
            optimizer.zero_grad()

            hidden = model.init_hidden(B)
            if isinstance(hidden, tuple):
                hidden = tuple(h.detach() for h in hidden)
            else:
                hidden = hidden.detach()

            logits, _ = model(inputs, hidden)        # (B, T, V)
            B2, T, V  = logits.shape
            loss = criterion(logits.reshape(B2 * T, V),
                             targets.reshape(B2 * T))
            loss.backward()
            nn.utils.clip_grad_norm_(model.parameters(), max_norm=3.0)
            optimizer.step()
            total_loss += loss.item()

        scheduler.step()
        avg_loss = total_loss / len(dataloader)
        loss_history.append(avg_loss)
        if epoch % 20 == 0:
            print(f'  [{model_name}] Epoch {epoch:3d}/{num_epochs} | Loss: {avg_loss:.4f}')

    return loss_history

NUM_EPOCHS = 120
print('Training Vanilla RNN...')
rnn_losses   = train_model(rnn_model,   dataloader, NUM_EPOCHS,
                            lr=0.002, weight_decay=1e-4, model_name='VanillaRNN')
print('\nTraining LSTM (2-layer)...')
blstm_losses = train_model(blstm_model, dataloader, NUM_EPOCHS,
                            lr=0.002, weight_decay=1e-4, model_name='LSTM')
print('\nTraining RNN+CausalAttn...')
attn_losses  = train_model(attn_model,  dataloader, NUM_EPOCHS,
                            lr=0.002, weight_decay=1e-4, model_name='RNN+CausalAttn')
print('\nAll models trained.')

# ============================================================
# Training Loss Curves
# ============================================================
import matplotlib.pyplot as plt

plt.figure(figsize=(10, 5))
plt.plot(rnn_losses,   label='Vanilla RNN',    color='#e74c3c')
plt.plot(blstm_losses, label='BiLSTM',         color='#3498db')
plt.plot(attn_losses,  label='RNN+Attention',  color='#2ecc71')
plt.xlabel('Epoch')
