# ============================================================
# FIXED Name Generation — single-token autoregressive loop
# ============================================================

def generate_name(model, max_len=15, temperature=0.8, min_len=3):
    """
    Correct autoregressive generation:
      1. Initialise hidden state to zeros.
      2. Feed SOS token → get hidden, logits.
      3. Sample next char from logits.
      4. Feed ONLY that char (not the whole history) with the updated hidden.
      5. Repeat until EOS or max_len.

    temperature: <1 → sharper/more confident, >1 → more random
    min_len: refuse to emit EOS before this many characters
    """
    model.eval()
    with torch.no_grad():
        hidden = model.init_hidden(1)
        inp    = torch.tensor([[SOS_IDX]], dtype=torch.long).to(DEVICE)
        name_chars = []

        for step in range(max_len):
            logits, hidden = model(inp, hidden)     # (1, 1, V)
            logits = logits[0, -1, :] / temperature # (V,)

            # Suppress PAD and SOS tokens always
            logits[PAD_IDX] = float('-inf')
            logits[SOS_IDX] = float('-inf')

            # Enforce minimum name length
            if step < min_len:
                logits[EOS_IDX] = float('-inf')

            probs = F.softmax(logits, dim=-1)
            idx   = torch.multinomial(probs, 1).item()

            if idx == EOS_IDX:
                break
            name_chars.append(idx2char[idx])
            # Feed ONLY this single new token (key fix)
            inp = torch.tensor([[idx]], dtype=torch.long).to(DEVICE)

    name = ''.join(name_chars)
    # Post-process: must be at least min_len chars and only alpha
    name = ''.join(c for c in name if c.isalpha())
    return name.capitalize() if len(name) >= min_len else ''


def generate_names_batch(model, n=200, temperature=0.8):
    """Generate n valid names, retrying until n valid ones are collected."""
    names, attempts = [], 0
    while len(names) < n and attempts < n * 5:
        nm = generate_name(model, temperature=temperature)
        if nm:
            names.append(nm)
        attempts += 1
    return names


# ============================================================
# TASK 2: Compute Novelty Rate and Diversity
# ============================================================
N_GENERATE   = 200
TRAINING_SET = set(n.lower() for n in training_names)

def evaluate_model(model, model_name, n=N_GENERATE, temperature=0.8):
    generated = generate_names_batch(model, n=n, temperature=temperature)
    valid     = [nm for nm in generated if len(nm) >= 3]
    if not valid:
        return {'model': model_name, 'total': 0, 'novel': 0,
                'unique': 0, 'novelty': 0.0, 'diversity': 0.0,
                'generated': []}

    novel     = [nm for nm in valid if nm.lower() not in TRAINING_SET]
    unique    = set(valid)
    novelty   = len(novel)  / len(valid) * 100
    diversity = len(unique) / len(valid) * 100
    return {'model': model_name, 'total': len(valid),
            'novel': len(novel), 'unique': len(unique),
            'novelty': novelty, 'diversity': diversity,
            'generated': valid}

print('Evaluating models (generating 200 names each)...')
results = {}
MODEL_LABELS = [('VanillaRNN', rnn_model),
                ('LSTM',       blstm_model),
                ('RNN+CausalAttn', attn_model)]
for nm, mdl in MODEL_LABELS:
    results[nm] = evaluate_model(mdl, nm)
    print(f'  {nm} → sample: {results[nm]["generated"][:5]}')

print('\n' + '=' * 60)
print('  QUANTITATIVE EVALUATION RESULTS')
print('=' * 60)
print(f'  {"Model":<20} {"Total":>6} {"Novel":>6} {"Unique":>6} '
      f'{"Novelty%":>10} {"Diversity%":>12}')
print('  ' + '-' * 60)
for nm, r in results.items():
    print(f'  {nm:<20} {r["total"]:>6} {r["novel"]:>6} {r["unique"]:>6} '
          f'{r["novelty"]:>9.1f}% {r["diversity"]:>11.1f}%')
print('=' * 60)

